select count(PRINTSQ) as PRINTCOUNT
  from SPRTHI
where COMPKEY = #{userData.compkey}

		and BLDDCKY = #{blhdcky}


		and BLDDCKY = #{bthdcky}


		and BLDDCKY = #{bthdcky}
		and BLDDCIT = #{docitem}

{
	/* bmAddPrintList */
	CALL SP_SY_SPRTHI (#{userData.compkey}, #{warekey}, #{doccate},
	#{doctype},
	#{progrid}, #{dochkey}, #{docitem}, #{userData.useract},
	#{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=VARCHAR})	
}

select TELPHNM
  from V_SUSRMA
 where COMPKEY = #{compkey}
   and USERACT = #{useract}
